mapper.update:
update comp_team
status = #{status}, current_members = #{currentMembers}, team_name = #{teamName}, update_by = #{updateBy}, update_time = sysdate()
where team_id = #{teamId}

update comp_team
set del_flag = '2', update_time = sysdate()
where team_id = #{teamId}

mapper.select:
select count(1)
from comp_team_member m
inner join comp_team t on t.team_id = m.team_id and t.del_flag = '0'
where t.competition_id = #{competitionId}
  and m.user_id = #{userId}
  and m.del_flag = '0'

select t.*, c.competition_name, as comp_status, c.category_name, c.category from comp_team t left join competition c on t.competition_id = c.competition_id where t.is_public = '1' and t.status = '0' and t.del_flag = '0'
and t.competition_id = #{competitionId}
order by t.create_time desc

mapper.update:
update comp_team
set status = '1', update_time = sysdate()
where team_id  = #{teamId}
  and status   = '0'
  and del_flag = '0'
  and leader_id = #{leaderId}
